import React, { useState, useEffect, useContext } from 'react';
import { AuthContext } from '../context/AuthContext';
import axios from 'axios';

const DoctorDashboard = () => {
  const { user } = useContext(AuthContext);

  const [appointmentsToday, setAppointmentsToday] = useState([]);
  const [availability, setAvailability] = useState([]);
  const [patients, setPatients] = useState([]);
  const [appointmentHistory, setAppointmentHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  const fetchDashboardData = async () => {
    try {
      const token = localStorage.getItem('token');
      const config = { headers: { Authorization: `Bearer ${token}` } };

      const [
        appointmentsRes,
        historyRes,
        availabilityRes,
        patientsRes
      ] = await Promise.all([
        axios.get('/api/doctor/today-appointments', config),
        axios.get('/api/doctor/appointment-history', config),
        axios.get('/api/doctor/availability', config),
        axios.get('/api/doctor/patients', config)
      ]);

      setAppointmentsToday(appointmentsRes.data);
      setAppointmentHistory(historyRes.data);
      setAvailability(availabilityRes.data);
      setPatients(patientsRes.data);
    } catch (err) {
      console.error(err);
      setError('Failed to load dashboard data.');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (user?.role === 'Doctor') {
      fetchDashboardData();
    }
  }, [user]);

  if (!user || user.role !== 'Doctor') {
    return <div className="text-red-600 text-center text-xl mt-10">Access Denied: Doctors Only</div>;
  }

  if (loading) return <p className="text-center mt-10">Loading...</p>;
  if (error) return <p className="text-center mt-10 text-red-600">{error}</p>;

  return (
      <div className="max-w-7xl mx-auto p-6 text-gray-800">
        <h1 className="text-3xl font-bold mb-6 text-center text-green-700">Doctor Dashboard</h1>

        {/* Today's Appointments */}
        <section className="bg-white p-5 rounded shadow mb-6">
          <h2 className="text-xl font-semibold mb-4">Today's Appointments</h2>
          {appointmentsToday.length === 0 ? (
              <p>No appointments scheduled for today.</p>
          ) : (
              <table className="w-full table-auto border text-sm">
                <thead className="bg-green-100">
                <tr>
                  <th className="px-3 py-2">Patient</th>
                  <th className="px-3 py-2">Time</th>
                  <th className="px-3 py-2">Status</th>
                </tr>
                </thead>
                <tbody>
                {appointmentsToday.map((appt) => (
                    <tr key={appt.id} className="border-t">
                      <td className="px-3 py-2">{appt.patientName}</td>
                      <td className="px-3 py-2">{appt.time}</td>
                      <td className="px-3 py-2">{appt.status}</td>
                    </tr>
                ))}
                </tbody>
              </table>
          )}
        </section>

        {/* Availability Table */}
        <section className="bg-white p-5 rounded shadow mb-6">
          <h2 className="text-xl font-semibold mb-4">Availability</h2>
          {availability.length === 0 ? (
              <p>No availability set.</p>
          ) : (
              <table className="w-full table-auto border text-sm">
                <thead className="bg-green-100">
                <tr>
                  <th className="px-3 py-2">Date</th>
                  <th className="px-3 py-2">Time Slots</th>
                </tr>
                </thead>
                <tbody>
                {availability.map((slot) => (
                    <tr key={slot.id} className="border-t">
                      <td className="px-3 py-2">{slot.date}</td>
                      <td className="px-3 py-2">{slot.timeSlots.join(', ')}</td>
                    </tr>
                ))}
                </tbody>
              </table>
          )}
        </section>

        {/* Patients Table */}
        <section className="bg-white p-5 rounded shadow mb-6">
          <h2 className="text-xl font-semibold mb-4">Patients</h2>
          {patients.length === 0 ? (
              <p>No patients found.</p>
          ) : (
              <table className="w-full table-auto border text-sm">
                <thead className="bg-green-100">
                <tr>
                  <th className="px-3 py-2">Name</th>
                  <th className="px-3 py-2">Last Visit</th>
                </tr>
                </thead>
                <tbody>
                {patients.map((patient) => (
                    <tr key={patient.id} className="border-t">
                      <td className="px-3 py-2">{patient.name}</td>
                      <td className="px-3 py-2">{patient.lastVisit}</td>
                    </tr>
                ))}
                </tbody>
              </table>
          )}
        </section>

        {/* Appointment History */}
        <section className="bg-white p-5 rounded shadow mb-6">
          <h2 className="text-xl font-semibold mb-4">Appointment History</h2>
          {appointmentHistory.length === 0 ? (
              <p>No appointment history available.</p>
          ) : (
              <table className="w-full table-auto border text-sm">
                <thead className="bg-green-100">
                <tr>
                  <th className="px-3 py-2">Patient</th>
                  <th className="px-3 py-2">Date</th>
                  <th className="px-3 py-2">Status</th>
                </tr>
                </thead>
                <tbody>
                {appointmentHistory.map((record) => (
                    <tr key={record.id} className="border-t">
                      <td className="px-3 py-2">{record.patientName}</td>
                      <td className="px-3 py-2">{record.date}</td>
                      <td className="px-3 py-2">{record.status}</td>
                    </tr>
                ))}
                </tbody>
              </table>
          )}
        </section>
      </div>
  );
};

export default DoctorDashboard;
